### SYSTEM 1: BULLET POOL (replace current projectile system)

Replace the `projectiles = []` array with a pre-allocated object pool:

```javascript
const BULLET_POOL_SIZE = 1500;
const bulletPool = [];
for (let i = 0; i < BULLET_POOL_SIZE; i++) {
  bulletPool.push({ alive: false, x: 0, y: 0, vx: 0, vy: 0, speed: 0, angle: 0, life: 0, color: '#ff0', type: 'normal', radius: 2 });
}

function spawnBullet(x, y, angle, speed, color, type, life) {
  for (let i = 0; i < BULLET_POOL_SIZE; i++) {
    if (!bulletPool[i].alive) {
      const b = bulletPool[i];
      b.alive = true;
      b.x = x; b.y = y;
      b.angle = angle;
      b.vx = Math.cos(angle) * speed;
      b.vy = Math.sin(angle) * speed;
      b.speed = speed;
      b.color = color;
      b.type = type || 'normal';
      b.life = life || 5;
      b.radius = type === 'large' ? 4 : 2;
      return b;
    }
  }
  return null; // pool exhausted
}

function killBullet(b) { b.alive = false; }

function forEachBullet(fn) {
  for (let i = 0; i < BULLET_POOL_SIZE; i++) {
    if (bulletPool[i].alive) fn(bulletPool[i]);
  }
}

function countAliveBullets() {
  let c = 0;
  for (let i = 0; i < BULLET_POOL_SIZE; i++) if (bulletPool[i].alive) c++;
  return c;
}
```

Update ALL code that currently uses `projectiles.push(createProjectile(...))` to use `spawnBullet()` instead. Update `updateProjectiles` to iterate the pool. Update `renderProjectiles` to iterate the pool. Remove the old `createProjectile` function and `projectiles` array.

