```javascript
window.GameEvents = (() => {
  const _listeners = {};

  return {
    on(event, fn) {
      (_listeners[event] ||= []).push(fn);
    },
    off(event, fn) {
      const arr = _listeners[event];
      if (arr) {
        const idx = arr.indexOf(fn);
        if (idx >= 0) arr.splice(idx, 1);
      }
    },
    emit(event, detail) {
      const arr = _listeners[event];
      if (!arr) return;
      for (let i = 0; i < arr.length; i++) arr[i](detail);
    },
    clear() {
      for (const key in _listeners) delete _listeners[key];
    }
  };
})();

