  ctx.lineTo(mx - bottomWidth/2, beamBottom);
  ctx.lineTo(mx + bottomWidth/2, beamBottom);
  ctx.lineTo(mx + topWidth/2, beamTop);
  ctx.closePath();
  ctx.fill();

  // Ground spotlight (brighter rectangle on ground)
  ctx.globalAlpha = 0.1;
  ctx.fillStyle = '#ffcc66';
  ctx.fillRect(Math.floor(mx - bottomWidth/2), H - 32, bottomWidth, 32);

  ctx.globalAlpha = 1;
}
